mapper.select:
SELECT id, protocol_id, http_url, http_method, http_headers, timeout, retry_times, status, create_time, update_time
FROM mcp_protocol_http
WHERE protocol_id = #{protocolId}

SELECT id, protocol_id, http_url, http_method, http_headers, timeout, retry_times, status, create_time, update_time
FROM mcp_protocol_http


        AND protocol_id = #{protocolId}


        AND http_url like concat('%', #{httpUrl}, '%')


ORDER BY update_time DESC

    LIMIT #{limitStart}, #{limitCount}

SELECT count(id) FROM mcp_protocol_http
AND protocol_id = #{protocolId}
AND http_url like concat('%', #{httpUrl}, '%')
